INSERT INTO public.photos VALUES (26063, 'Vista 1903', 'Imagen del caserâ”śÂˇo urbano capturada desde la altura de la entonces barroca torre de la iglesia parroquial de Santa Marâ”śÂˇa Magdalena, orientada hacia el occidente siguiendo la traza del antiguo "decumano maximo", identificado con la estrecha cinta oscura de la calle Mayor, a la izquierda. En primer tâ”śÂ®rmino, tejados recayentes a la perpendicular calle de Tomâ”śĂ­s Fermâ”śÂˇn Lezaun, que comunica con la paralela calle de Don Juan de Aragâ”śâ”‚n, en cuyo nâ”¬â•‘ 15 estuvo ubicada la primera escuela municipal de niâ”śâ–’as, luego sede de la Escuela Normal de Maestras; y en el nâ”¬â•‘ 11-13, la estructura del colegio de la Compaâ”śâ–’â”śÂˇa de las Hijas de la Caridad de San Vicente de Paâ”śâ•‘l, en una imagen antes de su gran ampliaciâ”śâ”‚n de 1909 para albergar el Asilo de la Coronaciâ”śâ”‚n para niâ”śâ–’os precarios. Hacia el fondo y a la derecha, techumbre, cimborrio y torre de la Seo sobre el frondoso fondo de la arboleda de Macanaz; el templo del Pilar con la torre de Santiago recayente a la homâ”śâ”‚nima plaza. Mâ”śĂ­s al fondo, meandro de Ranillas y el râ”śÂˇo Ebro curveando su cauce.', 1903, 1903, 1903, 'Anos 1900', 'CASCO HISTâ”śĂ´RICO', 41.65345100, -0.87482900, '0101000020E6100000CFF4126399FEEBBFED444948A4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49129512537.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49129512537.webp', 'https://www.flickr.com/photos/zaragozaantigua/49129512537/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20888, 'Apariciâ”śâ”‚n de la Virgen a Santiago aâ”śâ–’o 40', 'El apâ”śâ”‚stol Santiago y sus discâ”śÂˇpulos adorando a la Virgen del Pilar, â”śâ”‚leo sobre lienzo, Francisco de Goya, 1775. Escena pintada por Goya para la basâ”śÂˇlica del Pilar que, sin embargo, permaneciâ”śâ”‚ en manos de la Fundaciâ”śâ”‚n Rosillo hasta que la subastâ”śâ”‚ en 2011. Y es que, como decâ”śÂˇa don Francisco, "En hablando de pintura y Zaragoza, me quemo vivo". El momento representado es aquâ”śÂ®l del 2 de enero del aâ”śâ–’o 40 en que, segâ”śâ•‘n la tradiciâ”śâ”‚n, mientras Santiago y sus discâ”śÂˇpulos rezaban a orillas del Ebro, junto a las murallas romanas, "Marâ”śÂˇa Santâ”śÂˇsima vino en carne mortal a Zaragoza", acompaâ”śâ–’ada de unos â”śĂ­ngeles portadores de una columna de jaspe de regalo, sobre la que (como vemos), se posâ”śâ”‚ la madre de Jesâ”śâ•‘s, cual Simeâ”śâ”‚n el Estilita. Fuente: somoszaragoza.wordpress.com/2011/03/11/el-apostol-santiag...', NULL, NULL, NULL, NULL, 'CASCO HISTâ”śĂ´RICO', 41.65726000, -0.87757900, '0101000020E61000001901158E2015ECBF077C7E1821D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14996824859.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14996824859.webp', 'https://www.flickr.com/photos/zaragozaantigua/14996824859/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22229, 'La Romareda c.1957', 'El reciâ”śÂ®n inaugurado estadio municipal de La Romareda, en una imagen capturada desde la tribuna este, con vista parcial de la grada de gol sur, a la izquierda, que confronta con el convento de Jerusalâ”śÂ®n, y de la tribuna oeste. Al fondo, el moderno Seminario Metropolitano, tras la carretera de Valencia y algunas de las torres que la jalonaban entre campos de cultivo.', 1957, 1957, 1957, 'Anos 50', 'UNIVERSIDAD', 41.63622900, -0.90259500, '0101000020E6100000520FD1E80EE2ECBF26E2ADF36FD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49877267146.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49877267146.webp', 'https://www.flickr.com/photos/zaragozaantigua/49877267146/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20983, 'Escorredero de los Puentecitos 1832', '"Mapa topogrâ”śĂ­fico hidrâ”śĂ­ulico que representa con todas sus particularidades câ”śâ”‚mo se halla al presente una porciâ”śâ”‚n de terreno a derecha e izquierda de la acequia o escorredero del tâ”śÂ®rmino del Rabal llamado los Puentecitos y camino de la Arboleda de Macanaz y Herederos en las inmediaciones del Arrabal de Zaragoza", Antonio Vicente y Juan Mendoza, 10 de marzo de 1832. Tramo de la red de acequias de la margen izquierda de Zaragoza, en el que se instalâ”śâ”‚ un lavadero. A la izquierda, fuera de plano, el râ”śÂˇo Ebro, entre el puente de Piedra y la arboleda de Macanaz (arriba). A la derecha, confluencia del escorredero de la Ortilla y el de las Balsas de Ebro Viejo. Fuente: AMZ.', 1832, 1832, 1832, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65886700, -0.87676200, '0101000020E610000086048C2E6F0EECBFF2B4FCC055D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21033067406.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21033067406.webp', 'https://www.flickr.com/photos/zaragozaantigua/21033067406/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20998, 'El Pilar c.1805', 'Grabado realizado por Francisco â”śĂ¬â”śâ–’iguez Almech que captura el saliente momento de una "Procesiâ”śâ”‚n en la Capilla de la Virgen de la Basâ”śÂˇlica del Pilar de Zaragoza", con el magnâ”śÂˇfico enmarque escâ”śÂ®nico de la Capilla de la Virgen diseâ”śâ–’ada por Ventura Rodrâ”śÂˇguez a finales del siglo XVIII, que solucionaba la inserciâ”śâ”‚n del espacio de la antigua Capilla dentro de la cobertura barroca del nuevo templo del Pilar por medio de un esmerado conjunto arquitectâ”śâ”‚nico sumamente ingenioso. Fuente visual: Escuela Tâ”śÂ®cnica Superior de Arquitectura de la Universidad de Navarra.', 1805, 1805, 1805, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65663800, -0.87814400, '0101000020E61000004AB72572C119ECBFCAA7C7B60CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39383962864.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39383962864.webp', 'https://www.flickr.com/photos/zaragozaantigua/39383962864/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21004, 'El Pilar c.1860', 'Colecciâ”śâ”‚n Madrazo, Madrid; familia Daza Campos, Madrid (Adquirido en 2006 por el Museo del Prado). Autor anâ”śâ”‚nimo. Antes de 1880. "Vista posterior de la Basâ”śÂˇlica del Pilar de Zaragoza." Aâ”śâ•‘n no ha sido construida la câ”śâ•‘pula central. En la parte del râ”śÂˇo, montones de maderos apilados (secâ”śĂ­ndose) para la obra del Pilar. Son maderos que eran bajados desde el navarro valle del Roncal, por râ”śÂˇos como el Aragâ”śâ”‚n, y el Ebro. La câ”śâ•‘pula central fue levantada entre 1866 y 1869, de forma que la fecha datada ("antes de 1880") es muy cierta.', 1860, 1860, 1860, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65691400, -0.87812300, '0101000020E61000006CB1DB679519ECBF6C2409C215D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14723211268.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14723211268.webp', 'https://www.flickr.com/photos/zaragozaantigua/14723211268/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21031, 'El Pilar 1868', '"Saragossa - Cathedral del Pilar", foto Frank Mason Good. Vista del templo del Pilar en una imagen capturada confrontando desde la margen izquierda del Ebro, con detalle singular de la câ”śâ•‘pula central en proceso de construcciâ”śâ”‚n.', 1868, 1868, 1868, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65705500, -0.87832800, '0101000020E6100000A2276552431BECBF2E56D4601AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25873835924.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25873835924.webp', 'https://www.flickr.com/photos/zaragozaantigua/25873835924/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21071, 'RIberas del Ebro 1871', '"Zaragoza. Riberas del Ebro", dibujo de Francisco Pradilla, 1871. Al fondo, la margen izquierda del râ”śÂˇo Ebro a su paso por Zaragoza, con el convento de San Lâ”śĂ­zaro. A la derecha, el puente de Piedra. Fuente: carlosurzainqui.blogspot.com.es/2013/07/el-ebro-un-rio-de...', 1871, 1871, 1871, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65665700, -0.87718800, '0101000020E61000005D328E91EC11ECBF41D829560DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19017070455.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19017070455.webp', 'https://www.flickr.com/photos/zaragozaantigua/19017070455/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21163, 'El Pilar c.1890', 'Vista del râ”śÂˇo Ebro y su margen derecha, tomada desde el puente de Piedra de Zaragoza. Se ve el palacio de Ayerbe, las Casas de los Infantes y la basâ”śÂˇlica del Pilar. Fuente: Corbis Corporation', 1890, 1890, 1890, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65677600, -0.87701800, '0101000020E6100000431B800D8810ECBF1B66683C11D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20679993359.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20679993359.webp', 'https://www.flickr.com/photos/zaragozaantigua/20679993359/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21211, 'Paseo del Ebro c.1906', 'Un coche pasa bien despacito por la Ribera. No tiene marcas, pero "tos" saben que es la burguesâ”śÂˇa. Hemos volteado horizontalmente la imagen original, para que la tradiciâ”śâ”‚n mariana no quede descolocada, y se precipite la fin del mundo. Fuente visual: Estudio Coyne (DARA-AHPZ).', 1906, 1906, 1906, 'Anos 1900', 'CASCO HISTâ”śĂ´RICO', 41.65669200, -0.87724000, '0101000020E6100000FCC6D79E5912ECBFBDC5C37B0ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14964907111.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14964907111.webp', 'https://www.flickr.com/photos/zaragozaantigua/14964907111/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21280, 'Ebro y Pilar 1900', 'Postal "Zaragoza. Templo del Pilar". editada y publicada por la fototipia de Lucas Escolâ”śĂ­ para la Uniâ”śâ”‚n Postal Universal. La imagen captura la fachada al Ebro, desde la catedral de la Seo al templo del Pilar con la torre de Santiago (1715) recrecida y culminada unos aâ”śâ–’os antes.', 1900, 1900, 1900, 'Anos 1900', 'CASCO HISTâ”śĂ´RICO', 41.65725000, -0.87811200, '0101000020E6100000723447567E19ECBFE3A59BC420D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24730832995.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24730832995.webp', 'https://www.flickr.com/photos/zaragozaantigua/24730832995/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21566, 'Ribera del Ebro c.1925', '"Zaragoza. Pilar von Brâ”śâ•ťcke aus [El Pilar desde el Puente]". Desde la altura de las ordenadas piedras del tardomedieval puente de la ciudad sobre el Ebro, un vistazo hacia su margen derecha, con irrepetibles capturas, como la densa arboleda fluvial, y las estacas clavadas en el lecho del râ”śÂˇo que conformaban antiguas represas para mejorar el rendimiento de los molinos sobre el puente. Por encima del Palacio de los Marqueses de Ayerbe, despunta una de las dos originales câ”śâ•‘pulas que culminaban con aires franceses el comercial Pasaje del Ciclâ”śâ”‚n, antes de su consunciâ”śâ”‚n durante el incendio de 1926. Fuente visual: Archivo Wâ”śâ•ťnderlich (WUN-05819) www.mcu.es/fototeca_patrimonio/Visor?usarVisorMCU=true&am...', 1925, 1925, 1925, 'Anos 20', 'CASCO HISTâ”śĂ´RICO', 41.65677600, -0.87701800, '0101000020E6100000431B800D8810ECBF1B66683C11D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23209810293.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23209810293.webp', 'https://www.flickr.com/photos/zaragozaantigua/23209810293/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21797, 'Pilar c.1938', 'Imagen capturada desde un aeroplano en vuelo a baja altura sobre el Ebro y centrada en la ribereâ”śâ–’a fachada del templo del Pilar. Al fondo, a la izquierda, una insâ”śâ”‚lita visual de la torre de la desaparecida iglesia parroquial de San Juan y San Pedro, esquinera con la calle del Refugio. Fuente visual: www.todocoleccion.net/', 1938, 1938, 1938, 'Anos 30', 'CASCO HISTâ”śĂ´RICO', 41.65663800, -0.87814400, '0101000020E61000004AB72572C119ECBFCAA7C7B60CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25409042087.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25409042087.webp', 'https://www.flickr.com/photos/zaragozaantigua/25409042087/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
