INSERT INTO public.photos VALUES (21822, 'Râ”śÂˇo Ebro aâ”śâ–’os 30', 'Dos grupos de personas bien diferenciados pasean en barca por el râ”śÂˇo Ebro en Zaragoza. El remo marca la barrera social. Fuente: Heraldo de Aragâ”śâ”‚n.', 1930, 1930, 1939, 'Anos 30', 'CASCO HISTâ”śĂ´RICO', 41.65810900, -0.87811600, '0101000020E6100000CD04C3B98619ECBF051A6CEA3CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31993169606.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31993169606.webp', 'https://www.flickr.com/photos/zaragozaantigua/31993169606/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21892, 'Paseo del Ebro 1930', 'Imagen capturada en el hermoseado paseo del Ebro tras la finalizaciâ”śâ”‚n del proyecto de embellecimiento realizado segâ”śâ•‘n proyecto de Marcelo Carquâ”śÂ®. Un destacado nâ”śâ•‘mero de viandantes transita por el paseo a la altura del templo del Pilar.', 1930, 1930, 1930, 'Anos 30', 'CASCO HISTâ”śĂ´RICO', 41.65698600, -0.87745700, '0101000020E610000043AED4B32014ECBF06F7031E18D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49916655388.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49916655388.webp', 'https://www.flickr.com/photos/zaragozaantigua/49916655388/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21930, 'Ribera del Ebro nevada c.1946', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo (SF). Panorâ”śĂ­mica pergeâ”śâ–’ada para la ocasiâ”śâ”‚n, en una composiciâ”śâ”‚n inâ”śÂ®dita, democrâ”śĂ­tica, cientâ”śÂˇfica y popular, generada en los laboratorios del', 1946, 1946, 1946, 'Anos 40', 'CASCO HISTâ”śĂ´RICO', 41.65672400, -0.87662600, '0101000020E610000071581AF8510DECBFC83F33880FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14921469982.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14921469982.webp', 'https://www.flickr.com/photos/zaragozaantigua/14921469982/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21980, 'El Pilar aâ”śâ–’os 40', 'Ilustraciâ”śâ”‚n representando la basâ”śÂˇlica del Pilar de Zaragoza, vista desde el râ”śÂˇo Ebro. Inserta al principio del documental "Por el camino de la jota" (Francisco Centol, 1957). Fuente: www.flickr.com/photos/zaragozaantigua/25597475636/in/date...', 1940, 1940, 1949, 'Anos 40', 'CASCO HISTâ”śĂ´RICO', 41.65705500, -0.87832800, '0101000020E6100000A2276552431BECBF2E56D4601AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25464475613.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25464475613.webp', 'https://www.flickr.com/photos/zaragozaantigua/25464475613/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22070, 'Hielo en el Ebro 1956', 'Febrero de 1956. Un viento polar recorre la ciudad de Zaragoza. Tan frâ”śÂˇo, que los viejos del lugar recuerdan 1956 como "el aâ”śâ–’o de los cierzos heladores". En la imagen, visual cercana de los tormazos de hielo en el râ”śÂˇo Ebro y al fondo la margen izquierda y el puente de Piedra. Fuente: www.facebook.com/photo.php?fbid=1499530760298019&set=...', 1956, 1956, 1956, 'Anos 50', 'CASCO HISTâ”śĂ´RICO', 41.65747800, -0.87796800, '0101000020E6100000A7E7DD585018ECBF74EB353D28D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15200254584.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15200254584.webp', 'https://www.flickr.com/photos/zaragozaantigua/15200254584/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22192, 'Motos en el Pilar 1954', 'Festival del humor. Miembros del Moto Club Aragâ”śâ”‚n pasan en sus motos con sidecar santiguâ”śĂ­ndose ante el camarâ”śÂˇn de la Virgen del Pilar, blandiendo una pancarta con el nombre del club. Formaban parte del desfile de deportistas que a pie, en bicicleta o en motocicletas, tuvo lugar la medianoche del 9 al 10 de octubre como acto programado dentro del Congreso Mariano celebrado ese aâ”śâ–’o. Esta insâ”śâ”‚lita y ruidosa procesiâ”śâ”‚n motociclista entrâ”śâ”‚ al templo por el paseo de Echegaray y Caballero y saliâ”śâ”‚ por la plaza del Pilar. El Moto Club Aragâ”śâ”‚n fue fundado en 1922 por Luis Aperte, Josâ”śÂ® Luis Saâ”śâ–’udo, Ramâ”śâ”‚n Citoler y Fernando de Yarza, â”śÂ®ste padre de Pilar, luego presidenta de Heraldo de Aragâ”śâ”‚n. Los alcaldes Cesâ”śĂ­reo Alierta y Luis Gâ”śâ”‚mez Laguna fueron tambiâ”śÂ®n miembros de ese club, asâ”śÂˇ como del Movimiento Nacional. Fuente: Moto Club Aragâ”śâ”‚n.', 1954, 1954, 1954, 'Anos 50', 'CASCO HISTâ”śĂ´RICO', 41.65664600, -0.87818900, '0101000020E6100000499F56D11F1AECBF4D86E3F90CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32519647586.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32519647586.webp', 'https://www.flickr.com/photos/zaragozaantigua/32519647586/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22272, 'General Batista 1962', 'Archivo Municipal. Gerardo Sancho Ramo. 30/09/1962. "Visita del General Batista". Con el dictador Fulgencio Batista, un aliado confiable y un buen amigo de Occidente, algunas empresas de los EE.UU. de norteamâ”śÂ®rica poseâ”śÂˇan en Cuba el 40% de las tierras azucareras, casi todas las fincas de ganado, el 90% de las concesiones mineras, el 80% de los servicios y toda la industria del petrâ”śâ”‚leo, ademâ”śĂ­s de suministrar dos tercios de las importaciones del paâ”śÂˇs. Mientras eso fuera asâ”śÂˇ, la polâ”śÂˇtica interior del Râ”śÂ®gimen (era una de las dictaduras mâ”śĂ­s sangrientas y represivas del continente, lo que no era poco decir), era secundaria. Eran "cuestiones internas". Tras dos aâ”śâ–’os de lucha armada, fue derrocado por la Revoluciâ”śâ”‚n Cubana el 1 de enero de 1959, y huyâ”śâ”‚ de la isla con una fortuna estimada en 100 millones de dâ”śâ”‚lares. Se exiliâ”śâ”‚ primero en la Repâ”śâ•‘blica Dominicana, luego en la isla de Madeira (Portugal) y por â”śâ•‘ltimo en el Reino de Espaâ”śâ–’a, hasta su muerte (en 1973, de infarto) en el humilde municipio de Marbella. En la imagen, Fulgencio Batista (a la derecha, sin bigote), su seâ”śâ–’ora, y unos amigos, visitan a la Virgen del Pilar en sus estancias mâ”śĂ­s â”śÂˇntimas (el ropero), y todos estâ”śĂ­n encantadâ”śÂˇsimos.', 1962, 1962, 1962, 'Anos 60', 'CASCO HISTâ”śĂ´RICO', 41.65685700, -0.87808500, '0101000020E61000000C76C3B64519ECBF0893E2E313D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14937754782.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14937754782.webp', 'https://www.flickr.com/photos/zaragozaantigua/14937754782/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22425, 'El Pilar c.1965', 'Vista del Pilar reflejado en el Ebro. Fuente: Foto para postal de Comercial Josan. Cesiâ”śâ”‚n de la familia de Josâ”śÂ® Marâ”śÂˇa Sanz Gonzâ”śĂ­lez a Rafael Castillejo. Dataciâ”śâ”‚n y procesado:', 1965, 1965, 1965, 'Anos 60', 'CASCO HISTâ”śĂ´RICO', 41.65725000, -0.87811200, '0101000020E6100000723447567E19ECBFE3A59BC420D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27321899712.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27321899712.webp', 'https://www.flickr.com/photos/zaragozaantigua/27321899712/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22849, 'Guardabarrera Macanaz 1985', 'Imagen de la (habitada) casa del guardabarrera de Macanaz junto al antiguo, y desmantelado, enlace ferroviario entre la Estaciâ”śâ”‚n del Norte y la Estaciâ”śâ”‚n primero de Campo Sepulcro, luego Portillo, y la de Caminreal-Delicias. Esta caseta se situaba junto al viejo Camino de Ranillas, actual Arquitecto La Figuera-Paseo de la Ribera, en su confluencia con la calle Garcâ”śÂˇa Arista. Al fondo, la arboleda de Macanaz.', 1985, 1985, 1985, 'Anos 80', 'CASCO HISTâ”śĂ´RICO', 41.65942200, -0.87819800, '0101000020E610000016342DB1321AECBFA721AAF067D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15215303497.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15215303497.webp', 'https://www.flickr.com/photos/zaragozaantigua/15215303497/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23229, 'El Pilar aâ”śâ–’o 3978', '"Paco Pico y Pico Vena en: Regreso al planeta de los monos", viâ”śâ–’eta probablemente dibujada por Tha para El Jueves en los aâ”śâ–’os 90 del siglo XX, parodiando a Pedro Pico y Pico Vena en la escena â”śâ•‘ltima de la pelâ”śÂˇcula "El planeta de los simios" (1968). La pareja de personajes aludida (cuyo primer miembro cambia de nombre en esta versiâ”śâ”‚n) que sustituye al coronel George Taylor (Charlton Heston) es creaciâ”śâ”‚n de Carlos Azagra, dibujante que creciâ”śâ”‚ en Zaragoza. Vemos, en el lugar que en el filme ocupa la Estatua de la Libertad, la Basâ”śÂˇlica del Pilar de Zaragoza, en el aâ”śâ–’o en el que transcurre la ficciâ”śâ”‚n simiesca, 3978. Fuente: cazagra.blogspot.com.es/2008/04/charlton-heston-que-ests-...', 2024, 2020, 2029, 'Siglo XXI', 'CASCO HISTâ”śĂ´RICO', 41.65679500, -0.87838100, '0101000020E610000057B08D78B21BECBF9296CADB11D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15369805512.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15369805512.webp', 'https://www.flickr.com/photos/zaragozaantigua/15369805512/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23819, 'El Pilar 1862', 'Litografâ”śÂˇa de M. Fuster incluida en el libro "Historia crâ”śÂˇtica y apologâ”śÂ®tica de la Virgen Nuestra Seâ”śâ–’ora del Pilar de Zaragoza", Madrid, 1862.', 1862, 1862, 1862, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65725000, -0.87811200, '0101000020E6100000723447567E19ECBFE3A59BC420D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18898918754.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18898918754.webp', 'https://www.flickr.com/photos/zaragozaantigua/18898918754/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23845, 'Rayo en El Pilar 1798', '"Marâ”śÂˇa Santâ”śÂˇsima del Pilar de Zaragoza defendiendo a sus devotos de las terribles exhalaciones que cayeron en su angâ”śÂ®lica capilla la tarde del 5 de setiembre de 1798". Grabado de Mariano Latasa de 1804, editado posteriormente por Tomâ”śĂ­s Rocafort. El llamado "milagro de la centella" consistiâ”śâ”‚ en que el rayo que atravesâ”śâ”‚ la basâ”śÂˇlica en 1798 no daâ”śâ–’â”śâ”‚ a las personas que se encontraban allâ”śÂˇ. La sed de propaganda pilarista llevâ”śâ”‚ a conmemorar la fecha con celebraciones sacras en aâ”śâ–’os posteriores. En el dibujo, el rayo estâ”śĂ­ representado a la derecha, recorriendo la imagen completa de arriba abajo. Fuente: Fondo Documental Histâ”śâ”‚rico de las Cortes de Aragâ”śâ”‚n.', 1798, 1798, 1798, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65665600, -0.87817700, '0101000020E6100000382EE3A6061AECBF705CC64D0DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24469749609.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24469749609.webp', 'https://www.flickr.com/photos/zaragozaantigua/24469749609/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23847, 'El Pilar 1907', 'Foto: Petit. Basâ”śÂˇlica del Pilar en el otoâ”śâ–’o de 1907, reciâ”śÂ®n terminada la torre sureste. Fuente: Ministâ”śÂżre de la Culture (France) - Mâ”śÂ®diathâ”śÂżque de l''architecture et du patrimoine.', 1907, 1907, 1907, 'Anos 1900', 'CASCO HISTâ”śĂ´RICO', 41.65713500, -0.87839300, '0101000020E6100000682101A3CB1BECBF4A07EBFF1CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24575336213.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24575336213.webp', 'https://www.flickr.com/photos/zaragozaantigua/24575336213/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23849, 'El Pilar 1907', 'Foto: Lucien Roy. Vista del Pilar desde el Ebro. Acaba de levantarse la segunda torre, que aâ”śâ•‘n presenta andamios en su base. Fuente: Ministâ”śÂżre de la Culture (France) - Mâ”śÂ®diathâ”śÂżque de l''architecture et du patrimoine.', 1907, 1907, 1907, 'Anos 1900', 'CASCO HISTâ”śĂ´RICO', 41.65713500, -0.87839300, '0101000020E6100000682101A3CB1BECBF4A07EBFF1CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24851347299.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24851347299.webp', 'https://www.flickr.com/photos/zaragozaantigua/24851347299/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23860, 'Pilar c.1940', 'Fotografâ”śÂˇa convertida en popular postal capturando el interior de la dieciochesca capilla diseâ”śâ–’ada por Ventura Rodrâ”śÂˇguez para albergar al icono de la Virgen de Nâ”¬Â¬ Sâ”¬Â¬ del Pilar, en el templo del mismo nombre. El manto mariano que figura en la imagen fue ofrendado por Falange Espaâ”śâ–’ola para ser lucido con ocasiâ”śâ”‚n de los rituales aquâ”śÂˇ organizados por este partido polâ”śÂˇtico, una muestra de la â”śÂˇntima y simbiâ”śâ”‚tica relaciâ”śâ”‚n de este escenario de culto con el râ”śÂ®gimen surgido tras el 18 de julio de 1936. Fuente visual: www.todocoleccion.net/', 1940, 1940, 1940, 'Anos 40', 'CASCO HISTâ”śĂ´RICO', 41.65665600, -0.87817700, '0101000020E6100000382EE3A6061AECBF705CC64D0DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29733452623.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29733452623.webp', 'https://www.flickr.com/photos/zaragozaantigua/29733452623/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23869, 'Pilar y Fuensanta 1940', 'El aâ”śâ–’o 1940 fue prâ”śâ”‚digo en celebraciones zaragozanas nacional-catâ”śâ”‚licas, aprovechando la efemâ”śÂ®ride de la legendaria Venida de la Virgen, 1.900 aâ”śâ–’os antes, y reforzando la asfixiante propaganda de los nuevos poderes, tras la derrota militar de la democracia. El 18 de septiembre, Miguel de los Santos Dâ”śÂˇaz y Gomara, entonces obispo de Cartagena, comandâ”śâ”‚ una peregrinaciâ”śâ”‚n desde Murcia hasta Zaragoza, portando la imagen de la Virgen de la Fuensanta, patrona de Murcia. El tren que la llevaba contaba con un vagâ”śâ”‚n especial, dotado de un altar en el que reposaba la figura. El momento que recoge la foto es el del encuentro de la Virgen del Pilar (izquierda) con la Virgen de la Fuensanta (derecha), ambas con su criatura en brazos. Curioso caso de bilocaciâ”śâ”‚n representada, provista gracias al fenâ”śâ”‚meno de la advocaciâ”śâ”‚n mariana, que oferta multitud de denominaciones al personaje, convirtiâ”śÂ®ndolo en un grupo de fâ”śÂ®minas mâ”śÂˇticas diferenciadas. Fuente: www.laopiniondemurcia.es/', 1940, 1940, 1940, 'Anos 40', 'CASCO HISTâ”śĂ´RICO', 41.65673100, -0.87826600, '0101000020E6100000200A664CC11AECBF7BA2EBC20FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30724684240.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30724684240.webp', 'https://www.flickr.com/photos/zaragozaantigua/30724684240/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23879, 'Huelga General 1904', 'Chiste grâ”śĂ­fico realizado por Joaquâ”śÂˇn Moya, publicado en la revista satâ”śÂˇrica madrileâ”śâ–’a Gedeâ”śâ”‚n, en su nâ”śâ•‘mero 455, del 12 de agosto de 1904. Se hace referencia a la Huelga General de ese verano en Zaragoza. Al fondo, panorâ”śĂ­mica de la ciudad, incluyendo una factorâ”śÂˇa y el Pilar tras el râ”śÂˇo Ebro. Fuente: Biblioteca Nacional de Espaâ”śâ–’a.', 1904, 1904, 1904, 'Anos 1900', 'CASCO HISTâ”śĂ´RICO', 41.65870300, -0.87700000, '0101000020E6100000AAF1D24D6210ECBF7863416150D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31159510676.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31159510676.webp', 'https://www.flickr.com/photos/zaragozaantigua/31159510676/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23890, 'Goya en Zaragoza 1781', '"Goya en Zaragoza", dibujo de Josâ”śÂ® Luis Cano que representa al pintor Francisco de Goya pintando la câ”śâ•‘pula "Regina Martyrum" en el Pilar de Zaragoza. Es câ”śÂ®lebre su enfrentamiento con el cabildo a causa del estilo de esta pintura. Fuente: "Zaragoza nuestra ciudad", Ayuntamiento de Zaragoza, 1983.', 1781, 1781, 1781, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65679800, -0.87812500, '0101000020E61000009A9999999919ECBF030AF5F411D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32186749735.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32186749735.webp', 'https://www.flickr.com/photos/zaragozaantigua/32186749735/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23895, 'El cojo de Calanda 1638', 'Cuenta la leyenda que Miguel Juan Pellicer Blasco, nacido en Calanda en 1617, tuvo un accidente de carro en Castellâ”śâ”‚n en 1637, que le fracturâ”śâ”‚ la tibia derecha. Trasladado al Hospital Real de Valencia y luego al Hospital Nuestra Seâ”śâ–’ora de Gracia de Zaragoza, le amputan la pierna por estar gangrenada y la entierran en el cementerio de este â”śâ•‘ltimo hospital. En 1638 se le coloca una pierna de madera y se le surte de una muleta. Con estas armas pide limosna en la puerta del templo mudâ”śÂ®jar del Pilar y entra a untarse el muâ”śâ–’â”śâ”‚n con aceite de las lâ”śĂ­mparas, momento que recoge la imagen. En 1640 viaja a su pueblo natal, donde la Virgen del Pilar le repone la pierna mientras duerme, incluyendo sus antiguas marcas: un mal grano, unos rasguâ”śâ–’os y un mordisco de perro. Este fenâ”śâ”‚meno le hace famoso, hasta el punto de ser recibido por el rey, Felipe IV. Fuera el desgaste de la fama o que la Virgen del Pilar estaba ocupada en otros asuntos, Miguel falleciâ”śâ”‚ en Velilla de Ebro a los 30 aâ”śâ–’os. Pero no por eso se le olvidâ”śâ”‚: un paisano suyo, Luis Buâ”śâ–’uel, escogiâ”śâ”‚ la novela de Galdâ”śâ”‚s "Tristana" para hacer una pelâ”śÂˇcula, porque â”śÂ®sta perdâ”śÂˇa una pierna. Y casi cuatro siglos despuâ”śÂ®s, continâ”śâ•‘a habiendo muchas personas que toman por real la milagrosa anâ”śÂ®cdota del cojo de Calanda. Fuente visual: Fragmento de pintura mural de la iglesia de Nuestra Seâ”śâ–’ora del Pilar en Calanda.', 1638, 1638, 1638, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65663800, -0.87814400, '0101000020E61000004AB72572C119ECBFCAA7C7B60CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35753110784.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35753110784.webp', 'https://www.flickr.com/photos/zaragozaantigua/35753110784/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22259, 'Campo de fâ”śâ•‘tbol de la Romareda 1960', '1960. Al fondo a la derecha, el Seminario.', 1960, 1960, 1960, 'Anos 60', 'UNIVERSIDAD', 41.63629300, -0.90183000, '0101000020E61000005DA79196CADBECBF3DD68C0C72D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14728546019.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14728546019.webp', 'https://www.flickr.com/photos/zaragozaantigua/14728546019/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23900, 'El Pilar c.1907', 'Imagen capturada en la arboleda de Macanaz y centrada en el lienzo norteâ”śâ–’o del templo del Pilar recayente a la ribera del râ”śÂˇo Ebro, que fluye parsimonioso en primer tâ”śÂ®rmino. La gran câ”śâ•‘pula central aparece flanqueada de las dos torres culminadas pocos aâ”śâ–’os antes. A la izquierda, tras la Puerta del Retiro Bajo, el Colegio de los Infantes del Pilar. A la derecha, el antiguo postigo de Santa Marâ”śÂˇa del Pilar, sobre el que se dejan ver parcialmente las traseras de la que fuera antigua casa de Aytona.', 1907, 1907, 1907, 'Anos 1900', 'CASCO HISTâ”śĂ´RICO', 41.65716200, -0.87817600, '0101000020E6100000213A048E041AECBF441669E21DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49174723972.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49174723972.webp', 'https://www.flickr.com/photos/zaragozaantigua/49174723972/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23901, 'Asamblea Municipalista 1906', 'Dibujo satâ”śÂˇrico que reproduce a los mâ”śĂ­s notables dirigentes republicanos que participaron en la Asamblea Municipalista de Zaragoza, reunida entre el 9 y el 11 de febrero de 1906, en el teatro Pignatelli. Los personajes representan, cogidicos de la mano, como corresponde, el principio del "Coro y jota de los de Calatorao" que forma parte de la zarzuela "Gigantes y Cabezudos". Destaca por su tamaâ”śâ–’o, a la izquierda, Joaquâ”śÂˇn Costa, seguido de Alejandro Lerroux, Marcelino Isâ”śĂ­bal, Ricardo Fuente, y otros. La original letra de esta jota ("Por ver a la Pilarica, vengo de Calatoaro. Vinimos en la perrera, â”¬Ă­Jesâ”śâ•‘s, lo que hemos gastao!") ha sido modificada para la ocasiâ”śâ”‚n con rimante y republicano gracejo. Al fondo, el templo del Pilar aparece con la torre de Santiago, si bien la de Nuestra Seâ”śâ–’ora del Pilar, a la izquierda, ya se encontraba en proceso de culminaciâ”śâ”‚n.', 1906, 1906, 1906, 'Anos 1900', 'CASCO HISTâ”śĂ´RICO', 41.65858100, -0.87652400, '0101000020E61000006117450F7C0CECBF2C62D8614CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49203970382.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49203970382.webp', 'https://www.flickr.com/photos/zaragozaantigua/49203970382/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23972, 'Transfiguraciâ”śâ”‚n del Pilar 1974', 'Archivo Municipal de Zaragoza. Gerardo Sancho Ramo. 16/07/1974. "El Pilar." Imagen nocturna del templo mariano, cuya apariencia se hace blanca y resplandeciente, y asemeja rebosante de gloria celestial. O, en tâ”śÂ®rminos fâ”śÂˇsicos, simula una enana blanca (estrella frâ”śÂˇa estable, mantenida por la repulsiâ”śâ”‚n debida al principio de exclusiâ”śâ”‚n entre electrones). O a lo mejor es sâ”śâ”‚lo que han encendido la luz...', 1974, 1974, 1974, 'Anos 70', 'CASCO HISTâ”śĂ´RICO', 41.65686200, -0.87826100, '0101000020E6100000AE450BD0B61AECBF19FED30D14D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15127652420.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15127652420.webp', 'https://www.flickr.com/photos/zaragozaantigua/15127652420/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24772, 'C.â”¬â•‘ de Ranillas 1930', 'Apenas 15 centâ”śÂˇmetros por debajo de la marca de la oceâ”śĂ­nica inundaciâ”śâ”‚n de 1871, la "crecida" del Ebro de marzo de 1930 fue memorable. En el Arrabal, la situaciâ”śâ”‚n fue tremenda: las viviendas prâ”śâ”‚ximas al antiguo camino de Ranillas tuvieron que ser desalojadas, y las familias refugiadas provisionalmente en la Estaciâ”śâ”‚n del Norte. La imagen, capturada desde el tendido ferroviario que conectaba Zaragoza con Alsasua, ilustra los efectos de la riada en viviendas del Arrabal tras la rotura del muro de protecciâ”śâ”‚n. Las traseras de las casas de la izquierda formaban parte de las doce construidas recientemente por la "Cooperativa Hogar Obrero", con entrada por la calle Demetrio Galâ”śĂ­n (luego Garcâ”śÂˇa Arista). Las viviendas de la derecha, recayentes a la zona mâ”śĂ­s prâ”śâ”‚xima a la calle Sixto Celorrio. Toda esta zona llegarâ”śĂ­ mâ”śĂ­s o menos en estas condiciones (sin agua de inundaciâ”śâ”‚n), hasta finales de la dâ”śÂ®cada de los prodigiosos sesenta, en que serâ”śĂ­n derribadas las viejas casas, y sobre ellas, sus huertos y jardines traseros, y la amplia zona de huerta, se levantarâ”śĂ­n los grandes bloques habitacionales de hoy en dâ”śÂˇa. Las vâ”śÂˇas fâ”śÂ®rreas serâ”śĂ­n desmanteladas. Fuente visual: A de la Barrera, revista "Estampa" (Madrid).', 1930, 1930, 1930, 'Anos 30', 'CASCO HISTâ”śĂ´RICO', 41.65884700, -0.87649100, '0101000020E610000073A087DA360CECBFAB08371955D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22983190135.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22983190135.webp', 'https://www.flickr.com/photos/zaragozaantigua/22983190135/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24804, 'Crecida del Ebro 1930', 'Foto: Miguel Marâ”śÂˇn Chivite. Vista de las casas del Grupo Hogar Obrero, en el camino de Ranillas del Arrabal. La imagen estâ”śĂ­ tomada el 15 de marzo de 1930, durante la punta de la crecida del râ”śÂˇo Ebro de ese aâ”śâ–’o. Fuente: Heraldo de Aragâ”śâ”‚n.', 1930, 1930, 1930, 'Anos 30', 'CASCO HISTâ”śĂ´RICO', 41.65953900, -0.87765300, '0101000020E6100000AC8F87BEBB15ECBFE1B721C66BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33450501536.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33450501536.webp', 'https://www.flickr.com/photos/zaragozaantigua/33450501536/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24817, 'Vista Arrabal 1930', 'Imagen capturada desde la altura de la torre de Santiago del templo del Pilar, con una interesante vista panorâ”śĂ­mica del barrio del Arrabal, en la margen izquierda del râ”śÂˇo Ebro. La arboleda de Macanaz aparece inundada por la crecida de ese aâ”śâ–’o. En el centro de la escena, la iglesia de Nuestra Seâ”śâ–’ora de Altabâ”śĂ­s, la estaciâ”śâ”‚n del Norte ye industrias como Maquinista y Fundiciones del Ebro, S.A., la Nueva Harinera de Solans, y la azucarera del Arrabal. Hacia el fondo y a la derecha, la rectilâ”śÂˇnea avenida de Cataluâ”śâ–’a se dirige al puente del Gâ”śĂ­llego.', 1930, 1930, 1930, 'Anos 30', 'CASCO HISTâ”śĂ´RICO', 41.65846900, -0.87626600, '0101000020E6100000761893FE5E0AECBF043752B648D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49626790638.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49626790638.webp', 'https://www.flickr.com/photos/zaragozaantigua/49626790638/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24847, 'Concurso de aviaciâ”śâ”‚n 1911', 'Foto Pelayo. Revista Nuevo Mundo, 1911. Concurso de aviaciâ”śâ”‚n con la participaciâ”śâ”‚n de los pilotos Gaget y Frey. Convocado por el Ayuntamiento, que ofreciâ”śâ”‚ como premio la Copa de Zaragoza. Uno de los aeroplanos sobrevuela el Pilar, el Ebro y la Arboleda de Macanaz.', 1911, 1911, 1911, 'Anos 10', 'CASCO HISTâ”śĂ´RICO', 41.65725000, -0.87811200, '0101000020E6100000723447567E19ECBFE3A59BC420D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18944615669.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18944615669.webp', 'https://www.flickr.com/photos/zaragozaantigua/18944615669/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22382, 'Vista aâ”śÂ®rea Romareda 1964', 'Vista aâ”śÂ®rea centrada en el campo de fâ”śâ•‘tbol de la Romareda. A la derecha, el paseo de Isabel la Catâ”śâ”‚lica. Fuente visual : Fotografâ”śÂˇa aâ”śÂ®rea Lecar para el libro "El Ayuntamiento de Zaragoza", Colecciâ”śâ”‚n Rafael Margalâ”śÂ®.', 1964, 1964, 1964, 'Anos 60', 'UNIVERSIDAD', 41.63637700, -0.90173500, '0101000020E6100000EC12D55B03DBECBF9B7631CD74D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22326829231.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22326829231.webp', 'https://www.flickr.com/photos/zaragozaantigua/22326829231/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24855, 'Ebrobâ”śâ•‘s 2008', 'El martes 12 de agosto de 2008 y en el marco de la Expo, fue inaugurado el servicio de barcos recreativos en el râ”śÂˇo Ebro a su paso por Zaragoza, entre Vadorrey y Ranillas, bautizado como Ebrobâ”śâ•‘s (momento que recoge la imagen, con visual de los edificios del paseo de la Ribera, frente al Pilar). Como se ve en la foto, ademâ”śĂ­s de los dos embarcaderos en las ubicaciones citadas, se habilitâ”śâ”‚ un tercero en los bajos del Club Nâ”śĂ­utico. Para conseguir que el cauce fuese navegable, se construyâ”śâ”‚ en 2007 el azud Manuel Lorenzo Pardo, que en un principio iba a estar dotado de una estaciâ”śâ”‚n elâ”śÂ®ctrica para aprovechar el salto de agua (descartada) y que tambiâ”śÂ®n sirve de pasarela peatonal entre Las Fuentes y Vadorrey (â”śâ•‘nico uso que permanece). En octubre de ese mismo 2008 se inaugurâ”śâ”‚ una nueva tradiciâ”śâ”‚n pilarista: la Ofrenda Fluvial, procedente de Vadorrey y aprovechando este nuevo medio de transporte que pretendâ”śÂˇa emular a los Bateaux Mouches parisinos. Tras sus â”śâ•‘ltimos viajes en 2015, el servicio fue cancelado definitivamente en 2016, habida cuenta de que los câ”śĂ­lculos tâ”śÂ®cnicos acerca de la lâ”śĂ­mina de agua necesaria resultaron errados y era necesario dragar el cauce una y otra vez, sin conocimiento. La Ofrenda Fluvial permanece, en embarcaciones mâ”śĂ­s ligeras. Fuente visual: araclasicas.blogspot.com', 2008, 2008, 2008, 'Siglo XXI', 'CASCO HISTâ”śĂ´RICO', 41.65708700, -0.87683700, '0101000020E61000002F87DD770C0FECBF39D0436D1BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31182062015.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31182062015.webp', 'https://www.flickr.com/photos/zaragozaantigua/31182062015/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25105, 'Calle de Garcâ”śÂˇa Arista 1930', 'Imagen de â”śĂĽngel Bagâ”śâ•ťâ”śÂ®s, profesional barquero que conducâ”śÂˇa una embarcaciâ”śâ”‚n en el paso del Ebro que conectaba el pretil junto a San Juan de los Panetes hasta la arboleda de Macanaz, y que fue publicitado como "hâ”śÂ®roe de las inundaciones" por sus labores de rescate realizadas durante la gran salida de madre del râ”śÂˇo en marzo de 1930 (sâ”śâ”‚lo quince centâ”śÂˇmetros menos de altura que la monstruosa de 1871), cuando entre otras acciones condujo unos pontones hasta el Acampo de Urzâ”śĂ­iz, en Movera, para rescatar a varias personas encaramadas en lo alto de una tapia durante toda la noche a la espera de socorro. Preguntado por el nâ”śâ•‘mero de personas rescatadas en el râ”śÂˇo durante toda su vida, estimaba que "mâ”śĂ­s de un centenar". La foto fue realizada en su humilde vivienda inmediata al râ”śÂˇo en la calle de Gregorio Garcâ”śÂˇa Arista. En poco tiempo trocarâ”śÂˇa la tradicional barca de sirga de toda la vida por una moderna "gasolinera".', 1930, 1930, 1930, 'Anos 30', 'CASCO HISTâ”śĂ´RICO', 41.65910200, -0.87742500, '0101000020E61000006B2BF697DD13ECBF355D4F745DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52204216129.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52204216129.webp', 'https://www.flickr.com/photos/zaragozaantigua/52204216129/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25114, 'Bella perspectiva del Pilar 1982', 'Antonio Fraguas de Pablo, Forges, 1982. Ilustraciâ”śâ”‚n aparecida en la obra vendida por fascâ”śÂˇculos "Con ustedes... Forges ''82", sobre el Mundial de fâ”śâ•‘tbol de ese aâ”śâ–’o.', 1982, 1982, 1982, 'Anos 80', 'CASCO HISTâ”śĂ´RICO', 41.65686200, -0.87826100, '0101000020E6100000AE450BD0B61AECBF19FED30D14D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15035056736.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15035056736.webp', 'https://www.flickr.com/photos/zaragozaantigua/15035056736/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25444, 'Ribera Ebro 1950', 'Bajo la tercera arcada del puente de Piedra, que originalmente fue la cuarta, una vista parcial de la obra del nuevo ayuntamiento y del templo del Pilar con dos torres: la de Santiago, a la derecha, iniciada en 1715 y terminada en 1892, y la de Nuestra Seâ”śâ–’ora del Pilar, a la izquierda, construida entre 1903 y 1907. Del cauce del râ”śÂˇo sobresalen lâ”śÂˇneas de estacas que recuerdan las que reforzaban el azud o presa que encauzaba agua hacia los antiguos molinos harineros establecidos en el puente, entre ellos el molino de la ciudad. En la orilla del râ”śÂˇo se observa un ir y venir de gente buscando el refresco de la sombra y el agua. Hacia el fondo y a la derecha, la pasarela peatonal y las pilastras del puente del Ferrocarril. Fuente visual: www.ebay.es/', 1950, 1950, 1950, 'Anos 50', 'CASCO HISTâ”śĂ´RICO', 41.65683500, -0.87628700, '0101000020E6100000541EDD088B0AECBF20EF552B13D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31408029645.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31408029645.webp', 'https://www.flickr.com/photos/zaragozaantigua/31408029645/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25456, 'Râ”śÂˇo Ebro c.1950', 'Imagen del râ”śÂˇo Ebro centrada en el templo del Pilar y sus tradicionales torres recayentes a la homâ”śâ”‚nima plaza. Hacia el fondo, obras de construcciâ”śâ”‚n de la nueva Casa Consistorial sobre extenso solar donde estuviera, entre otros inmuebles, el palacio de los marqueses de Ayerbe. Una barca navega en direcciâ”śâ”‚n a la pasarela de Macanaz, cuya sombra se perfila sobre el tranquilo cauce fluvial.', 1950, 1950, 1950, 'Anos 50', 'CASCO HISTâ”śĂ´RICO', 41.65673700, -0.87821900, '0101000020E6100000F33977BB5E1AECBF5D8940F50FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49552670461.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49552670461.webp', 'https://www.flickr.com/photos/zaragozaantigua/49552670461/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25500, 'El Pilar 1877', 'Jean Laurent. 1877 "Iglesia de Nuestra Seâ”śâ–’ora del Pilar." De detalles, a veces, tambiâ”śÂ®n estâ”śĂ­ hecha la imagen: conjunciâ”śâ”‚n cupulativa con la â”śâ•‘nica torre incompleta, y Postigo de Aguadores o de Blancas.', 1877, 1877, 1877, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65668900, -0.87764000, '0101000020E6100000842A357BA015ECBF4C5299620ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15277775005.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15277775005.webp', 'https://www.flickr.com/photos/zaragozaantigua/15277775005/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25555, 'Arboleda de Macanaz 1907', 'Foto: Lucien Roy. Arboleda de Macanaz en la margen izquierda del râ”śÂˇo Ebro. Al fondo, el puente de Piedra y la torre de la Seo. Fuente: Ministâ”śÂżre de la Culture (France) - Mâ”śÂ®diathâ”śÂżque de l''architecture et du patrimoine.', 1907, 1907, 1907, 'Anos 1900', 'CASCO HISTâ”śĂ´RICO', 41.65882000, -0.87802700, '0101000020E6100000E5284014CC18ECBFB1F9B83654D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24847320929.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24847320929.webp', 'https://www.flickr.com/photos/zaragozaantigua/24847320929/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
